    protected function parsePreview(string $html, string $baseUrl): array
    {
        $title = null;
        $description = null;
        $image = null;
        $siteName = null;

        libxml_use_internal_errors(true);

        $doc = new \DOMDocument();
        $doc->loadHTML($html, LIBXML_NOWARNING | LIBXML_NOERROR);

        $xpath = new \DOMXPath($doc);

        $getMeta = function (string $attr, string $value) use ($xpath): ?string {
            $query = sprintf('//meta[translate(@%s,"ABCDEFGHIJKLMNOPQRSTUVWXYZ","abcdefghijklmnopqrstuvwxyz")="%s"]/@content', $attr, strtolower($value));
            $nodes = $xpath->query($query);
            if ($nodes && $nodes->length > 0) {
                $v = trim((string) $nodes->item(0)->nodeValue);
                return $v !== '' ? $v : null;
