    protected function absolutizeUrl(string $maybeUrl, string $baseUrl): string
    {
        $maybeUrl = trim($maybeUrl);

        if ($maybeUrl === '') {
            return $maybeUrl;
        }

        if (preg_match('~^https?://~i', $maybeUrl)) {
            return $maybeUrl;
        }

        if (str_starts_with($maybeUrl, '//')) {
            $scheme = parse_url($baseUrl, PHP_URL_SCHEME) ?: 'https';
            return $scheme . ':' . $maybeUrl;
        }

        $baseParts = parse_url($baseUrl);
        if (!$baseParts || empty($baseParts['host'])) {
            return $maybeUrl;
        }

        $scheme = $baseParts['scheme'] ?? 'https';
        $host = $baseParts['host'];
        $port = isset($baseParts['port']) ? ':' . $baseParts['port'] : '';
        $basePath = $baseParts['path'] ?? '/';
        $baseDir = preg_replace('~/[^/]*$~', '/', $basePath) ?: '/';

        if (str_starts_with($maybeUrl, '/')) {
            $path = $maybeUrl;
        } else {
            $path = $baseDir . $maybeUrl;
        }

        $path = $this->normalizePath($path);

        return $scheme . '://' . $host . $port . $path;
    }

    protected function normalizePath(string $path): string
    {
        $segments = explode('/', $path);
        $out = [];

        foreach ($segments as $seg) {
            if ($seg === '' || $seg === '.') {
                continue;
            }
            if ($seg === '..') {
                array_pop($out);
                continue;
            }
            $out[] = $seg;
        }

        return '/' . implode('/', $out);
    }
